/// Custom exception for HTTP service errors
class HttpServiceException implements Exception {
  final String message;
  final int? statusCode;
  final String? url;

  HttpServiceException(this.message, {this.statusCode, this.url});

  @override
  String toString() =>
      'HttpServiceException: $message${statusCode != null ? ' (Status: $statusCode)' : ''}${url != null ? ' [URL: $url]' : ''}';
}

/// Exception thrown when insecure traffic is attempted to a non-allowed host
class InsecureTrafficException implements Exception {
  final String host;

  InsecureTrafficException(this.host);

  @override
  String toString() =>
      'InsecureTrafficException: Cleartext HTTP traffic to "$host" is not permitted. '
      'Only local IoT device addresses (192.168.x.x) are allowed over HTTP.';
}

/// Allowed local network prefixes for cleartext HTTP traffic
class NetworkSecurityPolicy {
  /// Allowed IP prefixes that can use cleartext HTTP
  static const List<String> allowedCleartextPrefixes = [
    '192.168.',
    '10.',
    '172.16.',
    '172.17.',
    '172.18.',
    '172.19.',
    '172.20.',
    '172.21.',
    '172.22.',
    '172.23.',
    '172.24.',
    '172.25.',
    '172.26.',
    '172.27.',
    '172.28.',
    '172.29.',
    '172.30.',
    '172.31.',
    'localhost',
    '127.0.0.1',
  ];

  /// Check if cleartext HTTP is allowed for the given URI
  static bool isCleartextAllowed(Uri uri) {
    if (uri.scheme == 'https') return true;

    final host = uri.host;
    for (final prefix in allowedCleartextPrefixes) {
      if (host.startsWith(prefix) || host == prefix) {
        return true;
      }
    }
    return false;
  }
}

/// A secure HTTP client wrapper that enforces network security policy
class SecureHttpClient extends http.BaseClient {
  final http.Client _inner;

  SecureHttpClient(this._inner);

  @override
  Future<http.StreamedResponse> send(http.BaseRequest request) {
    if (!NetworkSecurityPolicy.isCleartextAllowed(request.url)) {
      throw InsecureTrafficException(request.url.host);
    }
    return _inner.send(request);
  }

  @override
  void close() {
    _inner.close();
  }
}

