// ==================== Usage Example ====================

Future<void> main() async {
  final httpService = HttpService(
    config: const HttpServiceConfig(
      cloudBaseUrl: 'https://api.example.com',
      timeout: Duration(seconds: 30),
      maxRetries: 3,
      allowSelfSignedCerts: true,
    ),
  );

  try {
    // --- Cloud API Examples ---

    // Set auth token
    httpService.setAuthToken('your-jwt-token-here');

    // GET from cloud
    print('--- Cloud GET ---');
    try {
      final cloudResponse = await httpService.cloudGet(
        '/api/v1/devices',
        queryParams: {'status': 'active'},
      );
      print('Cloud GET: ${cloudResponse.statusCode} - ${cloudResponse.data}');
    } on HttpServiceException catch (e) {
      print('Cloud GET failed: $e');
    }

    // POST to cloud
    print('\n--- Cloud POST ---');
    try {
      final postResponse = await httpService.cloudPost(
        '/api/v1/devices',
        body: {
          'name': 'Living Room Sensor',
          'type': 'temperature',
          'ip': '192.168.1.100',
        },
      );
      print(
          'Cloud POST: ${postResponse.statusCode} - ${postResponse.data}');
    } on HttpServiceException catch (e) {
      print('Cloud POST failed: $e');
    }

    // --- Insecure Traffic Prevention Demo ---
    print('\n--- Insecure Traffic Prevention ---');
    try {
      // This will throw InsecureTrafficException because
      // api.example.com is not a local network address
      final insecureUri = Uri.parse('http://api.example.com/api/v1/devices');
      print(
          'Is cleartext allowed for api.example.com? ${NetworkSecurityPolicy.isCleartextAllowed(insecureUri)}');

      // This would throw if attempted
      // await httpService.cloudGet('/api/v1/devices'); // with http:// scheme
    } on InsecureTrafficException catch (e) {
      print('Blocked: $e');
    }

    // --- IoT Device Examples ---

    // GET from IoT device
    print('\n--- IoT GET ---');
    try {
      final iotResponse = await httpService.iotGet(
        '192.168.1.100',
        '/api/status',
        port: 80,
      );
      print('IoT GET: ${iotResponse.statusCode} - ${iotResponse.data}');
    } on HttpServiceException catch (e) {
      print('IoT GET failed: $e');
    }

    // POST to IoT device
    print('\n--- IoT POST ---');
    try {
      final iotPostResponse = await httpService.iotPost(
        '192.168.1.100',
        '/api/config',
        port: 80,
        body: {
          'interval': 30,
          'unit': 'celsius',
        },
      );
      print(
          'IoT POST: ${iotPostResponse.statusCode} - ${iotPostResponse.data}');
    } on HttpServiceException catch (e) {
      print('IoT POST failed: $e');
    }

    // IoT device with HTTPS
    print('\n--- IoT HTTPS GET ---');
    try {
      final iotSecureResponse = await httpService.iotGet(
        '192.168.1.200',
        '/api/data',
        port: 443,
        scheme: 'https',
      );
      print(
          'IoT HTTPS GET: ${iotSecureResponse.statusCode} - ${iotSecureResponse.data}');
    } on HttpServiceException catch (e) {
      print('IoT HTTPS GET failed: $e');
    }

    // --- Attempt insecure request to non-local host ---
    print('\n--- Attempting insecure request to external host ---');
    try {
      await httpService.iotGet(
        'malicious-site.com',
        '/steal-data',
        scheme: 'http',
      );
    } on InsecureTrafficException catch (e) {
      print('Correctly blocked: $e');
    }

    // --- Network Security Policy Checks ---
    print('\n--- Network Security Policy Checks ---');
    final testUris = [
      Uri.parse('https://api.example.com/data'),
      Uri.parse('http://api.example.com/data'),
      Uri.parse('http://192.168.1.100/status'),
      Uri.parse('http://10.0.0.1/status'),
      Uri.parse('http://172.16.0.1/status'),
      Uri.parse('http://evil.com/hack'),
      Uri.parse('http://localhost:8080/test'),
      Uri.parse('http://127.0.0.1:3000/api'),
    ];

    for (final uri in testUris) {
      print(
          '  ${uri.toString().padRight(45)} -> Cleartext allowed: ${NetworkSecurityPolicy.isCleartextAllowed(uri)}');
    }

    // --- Device Discovery ---
    print('\n--- Device Discovery ---');
    try {
      final devices = await httpService.discoverDevices(
        '192.168.1',
        port: 80,
        path: '/api/status',
        timeout: const Duration(seconds: 1),
      );
      print('Discovered devices: $devices');
    } catch (e) {
      print('Discovery failed: $e');
    }
  } finally {
    httpService.dispose();
  }
}